+    );
+    assert_eq!(
+        LAST_SIGINFO_SIGNO.load(Ordering::Relaxed) as c_int,
+        libc::SIGUSR1,
+        "queued delivery should preserve the original signal number metadata"
+    );
+    assert_eq!(
+        LAST_SIGINFO_VALUE_BITS.load(Ordering::Relaxed),
